import{_ as i,o as a,c as t,ae as n}from"./chunks/framework.CyZiF_rV.js";const m=JSON.parse('{"title":"Invoice Verification","description":"","frontmatter":{},"headers":[],"relativePath":"en/faktury/weryfikacja-faktury.md","filePath":"en/faktury/weryfikacja-faktury.md"}'),o={name:"en/faktury/weryfikacja-faktury.md"};function r(l,e,s,c,d,h){return a(),t("div",null,[...e[0]||(e[0]=[n('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/faktury/weryfikacja-faktury.md" target="_blank" rel="noreferrer">faktury/weryfikacja-faktury.md</a></p></blockquote><h1 id="invoice-verification" tabindex="-1">Invoice Verification <a class="header-anchor" href="#invoice-verification" aria-label="Permalink to &quot;Invoice Verification&quot;">​</a></h1><p>15.01.2026</p><p>An invoice sent to the KSeF system undergoes a series of technical and semantic controls. Verification includes the following criteria:</p><h2 id="xsd-schema-compliance" tabindex="-1">XSD Schema Compliance <a class="header-anchor" href="#xsd-schema-compliance" aria-label="Permalink to &quot;XSD Schema Compliance&quot;">​</a></h2><p>The invoice must be prepared in XML format, encoded in UTF-8 without BOM signature (first 3 bytes 0xEF 0xBB 0xBF), compliant with the declared schema provided when opening the session.</p><h2 id="invoice-uniqueness" tabindex="-1">Invoice Uniqueness <a class="header-anchor" href="#invoice-uniqueness" aria-label="Permalink to &quot;Invoice Uniqueness&quot;">​</a></h2><ul><li>KSeF detects invoice duplicates globally, based on data stored in the system. The duplicate identification criterion consists of a combination of: <ol><li>Seller&#39;s NIP (<code>Podmiot1:NIP</code>)</li><li>Invoice type (<code>RodzajFaktury</code>)</li><li>Invoice number (<code>P_2</code>)</li></ol></li><li>In case of a duplicate, error code 440 (&quot;Invoice duplicate&quot;) is returned.</li><li>Invoice uniqueness is maintained in KSeF for a period of 10 full years, counted from the end of the calendar year in which the invoice was issued.</li><li>The uniqueness criterion always refers to the seller (Podmiot1:NIP). In cases where different units issue invoices on behalf of the same entity (e.g., branches, organizational units of local government entities, other authorized entities), they must agree on numbering rules to avoid duplicates.</li></ul><h2 id="date-validation" tabindex="-1">Date Validation <a class="header-anchor" href="#date-validation" aria-label="Permalink to &quot;Date Validation&quot;">​</a></h2><p>The invoice issue date (<code>P_1</code>) cannot be later than the date of document acceptance into the KSeF system.</p><h2 id="nip-number-validation" tabindex="-1">NIP Number Validation <a class="header-anchor" href="#nip-number-validation" aria-label="Permalink to &quot;NIP Number Validation&quot;">​</a></h2><ul><li>Verification of NIP checksum for: <code>Podmiot1</code>, <code>Podmiot2</code>, <code>Podmiot3</code> and <code>PodmiotUpowazniony</code> (if present).</li><li>Applies only to production environment.</li></ul><h2 id="nip-number-validation-in-internal-identifier" tabindex="-1">NIP Number Validation in Internal Identifier <a class="header-anchor" href="#nip-number-validation-in-internal-identifier" aria-label="Permalink to &quot;NIP Number Validation in Internal Identifier&quot;">​</a></h2><ul><li>Verification of NIP checksum in internal identifier (<code>InternalId</code>) for <code>Podmiot3</code> - if this identifier is present.</li><li>Applies only to production environment.</li></ul><h2 id="file-size" tabindex="-1">File Size <a class="header-anchor" href="#file-size" aria-label="Permalink to &quot;File Size&quot;">​</a></h2><ul><li>Maximum invoice size without attachments: <strong>1 MB *</strong> (1,000,000 bytes).</li><li>Maximum invoice size with attachments: <strong>3 MB *</strong> (3,000,000 bytes).</li></ul><h2 id="quantity-limitations" tabindex="-1">Quantity Limitations <a class="header-anchor" href="#quantity-limitations" aria-label="Permalink to &quot;Quantity Limitations&quot;">​</a></h2><ul><li>Maximum number of invoices in one session (both interactive and batch) is 10,000 *.</li><li>Within batch submission, you can send a maximum of 50 ZIP files; the size of each file before encryption cannot exceed 100 MB (100,000,000 bytes), and the total size of the ZIP package - 5 GB (5,000,000,000 bytes).</li></ul><h2 id="proper-encryption" tabindex="-1">Proper Encryption <a class="header-anchor" href="#proper-encryption" aria-label="Permalink to &quot;Proper Encryption&quot;">​</a></h2><ul><li>The invoice should be encrypted using AES-256-CBC algorithm (256-bit symmetric key, 128-bit IV, with PKCS#7 padding).</li><li>Symmetric key encrypted using RSAES-OAEP algorithm (SHA-256/MGF1).</li></ul><h2 id="invoice-metadata-compliance-in-interactive-session" tabindex="-1">Invoice Metadata Compliance in Interactive Session <a class="header-anchor" href="#invoice-metadata-compliance-in-interactive-session" aria-label="Permalink to &quot;Invoice Metadata Compliance in Interactive Session&quot;">​</a></h2><ul><li>Calculation and verification of invoice hash along with file size.</li><li>Calculation and verification of encrypted invoice hash along with file size.</li></ul><h2 id="attachment-limitations" tabindex="-1">Attachment Limitations <a class="header-anchor" href="#attachment-limitations" aria-label="Permalink to &quot;Attachment Limitations&quot;">​</a></h2><ul><li>Sending invoices with attachments is allowed only in batch mode.<br><strong>Exception:</strong> When sending <a href="./../offline/korekta-techniczna.html">technical correction of offline invoice</a>, the use of interactive session is permitted.</li><li>The ability to send invoices with attachments requires prior registration of this option in the <code>e-Tax Office</code> service.</li></ul><h2 id="authorization-requirements" tabindex="-1">Authorization Requirements <a class="header-anchor" href="#authorization-requirements" aria-label="Permalink to &quot;Authorization Requirements&quot;">​</a></h2><p>Sending an invoice to KSeF requires having appropriate permissions to issue it in the context of a given entity.</p><p>* <strong>Note:</strong> If the available <a href="./../limity/limity.html">limits</a> are insufficient for your organization&#39;s business scenarios, please contact KSeF support for individual analysis and selection of an appropriate solution.</p>',27)])])}const f=i(o,[["render",r]]);export{m as __pageData,f as default};
